// ============================================================
// JSONKB v1 — LOCATIONS
// Inputs (by node name):
// - Location – Detail
// - Get KB share file
// - Set KB folder defaults
// ============================================================

// ---------- pull inputs ----------
const dItems = $items("Location – Detail");
if (!dItems || dItems.length === 0) {
  throw new Error('JSONKB Locations: Missing input from node "Location – Detail".');
}
const row = dItems[0].json;



// ---------- helpers ----------
function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
}

function asNum(x) {
  if (x === null || x === undefined || x === '') return null;
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

function compactObj(obj) {
  if (!obj || typeof obj !== 'object') return obj;
  const out = Array.isArray(obj) ? [] : {};
  for (const [k, v] of Object.entries(obj)) {
    if (v === null || v === undefined) continue;

    if (typeof v === 'object' && !Array.isArray(v)) {
      const inner = compactObj(v);
      if (inner && Object.keys(inner).length) out[k] = inner;
      continue;
    }

    if (Array.isArray(v)) {
      if (v.length) out[k] = v;
      continue;
    }

    out[k] = v;
  }
  return out;
}

// deep-stable stringify (same as your v1.2 proof)
function stableStringify(value) {
  const seen = new WeakSet();
  function norm(v) {
    if (v === null || v === undefined) return v;

    if (typeof v === 'object') {
      if (seen.has(v)) return null;
      seen.add(v);

      if (Array.isArray(v)) return v.map(norm);

      const out = {};
      for (const k of Object.keys(v).sort()) out[k] = norm(v[k]);
      return out;
    }
    return v;
  }
  return JSON.stringify(norm(value));
}

// ---------- slug / name ----------
const name = row.name || row.location_name || 'Unknown Location';
const slug = slugify(row.slug || name);
if (!slug) throw new Error('JSONKB Locations: slug is empty.');

// ---------- kb_links (share must exist; markdown runs first) ----------

const kb_links = {
  kb_page_path: `/kb/${slug}`,
  kb_browse_path: `/browse?category=location`,
};

// ---------- deterministic kb_text ----------
const locationType = row.location_type || row.type || 'location';
const systemName = row.system_name || 'Unknown system';
const bodyOrOrbit = row.body_name_or_orbit || row.body_name || row.orbit_name || null;
const terminalsTotal = Number(row.terminals_total ?? row.terminals_count ?? 0) || 0;

let kb_text =
  `${name} is a ${locationType} located in the ${systemName} system.`;

if (bodyOrOrbit) {
  kb_text += ` It is associated with ${bodyOrOrbit}.`;
}

kb_text += ` It has ${terminalsTotal} trade terminals.`;

// ---------- entity_metadata ----------
let entity_metadata = {
  uex_location_id: row.uex_location_id != null ? Number(row.uex_location_id) : null,
  location_type: locationType || null,
  system_name: systemName || null,
  body_or_orbit: bodyOrOrbit,
  terminals_total: asNum(row.terminals_total ?? row.terminals_count) ?? terminalsTotal,
};

entity_metadata = compactObj(entity_metadata);

// ---------- rag_hints (locked-spec only; leave empty) ----------
const rag_hints = {
  sql_hints: [
    {
      id: "location.terminals",
      description: "Trade terminals at this location.",
      params: [{ name: "location_id", type: "uuid", required: true }],
      sql_template: `SELECT t.id, t.name, t.terminal_type
FROM trade_terminals t
WHERE t.location_id = :location_id
ORDER BY t.name;`
    }
  ],
  notes: null
};


// ---------- provenance ----------
const provenance = {
  generated_at: new Date().toISOString(),
  kb_generator_workflow: 'JSONKB - Locations v1',
  game_version: row.game_version || null,
  is_live_only: true,
};

// ---------- hash (single hash includes rag_hints) ----------
function fnv1a32Hex(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
function hash16(str) {
  const a = fnv1a32Hex(str);
  const b = fnv1a32Hex(str + '|v2');
  return a + b;
}

// ---------- JSONKB object ----------
const jsonkb = {
  kb_version: '1.0',

  entity_type: 'location',
  entity_id: row.id || null,
  entity_slug: slug,
  entity_name: name,

  source: 'uex',
  source_id: row.source_id || (row.uex_location_id != null ? `locations:${row.uex_location_id}` : (row.source_id || null)),
  source_table: 'locations',

  kb_text,
  kb_links,
  entity_metadata,
  rag_hints,
  provenance,
};

const hashBasis = stableStringify({
  entity_type: jsonkb.entity_type,
  entity_id: jsonkb.entity_id,
  kb_text: jsonkb.kb_text,
  entity_metadata: jsonkb.entity_metadata,
  rag_hints: jsonkb.rag_hints,
});

jsonkb.provenance.content_hash = hash16(hashBasis);

// ---------- JSONKB file path ----------
const jsonkb_file_path = `/kb/location/${slug}`;

return [
  {
    json: {
      location_id: row.id,
      slug,
      name,
      jsonkb,
      jsonkb_file_path,
    },
  },
];

